exercises.solution_code:
#include <iostream>
#include <iomanip>

int main()
{
    int iVal{};
    double dVal{};
    std::cin >> iVal >> dVal;

    void* vp1{ &iVal };
    void* vp2{ &dVal };

    std::cout << "int: " << *static_cast<int*>(vp1) << '\n';
    std::cout << std::fixed << std::setprecision(2);
    std::cout << "double: " << *static_cast<double*>(vp2) << '\n';

    return 0;
}

