exercises.solution_code:
#include <iostream>
#include <cstddef> // std::size_t

void swapBytes(void* p1, void* p2, std::size_t size)
{
    char* c1{ static_cast<char*>(p1) };
    char* c2{ static_cast<char*>(p2) };

    for (std::size_t i{ 0 }; i < size; ++i)
    {
        char tmp{ c1[i] };
        c1[i] = c2[i];
        c2[i] = tmp;
    }
}

int main()
{
    int a{};
    int b{};
    std::cin >> a >> b;

    std::cout << "Before: " << a << ' ' << b << '\n';
    swapBytes(&a, &b, sizeof(int));
    std::cout << "After: " << a << ' ' << b << '\n';

    return 0;
}
